import 'package:flutter/material.dart';

import '../../presentation/transcript_composer_presentation.dart';
import '../shared/transcript_bottom_sheet_list.dart';

class TranscriptComposer extends StatefulWidget {
  const TranscriptComposer({
    required this.controller,
    required this.onSend,
    this.voiceCaptureAvailable = false,
    this.voiceUnavailableReason,
    this.voiceRecoveryAction,
    this.onOpenVoiceSettings,
    this.onUploadFile,
    this.onPickPhotoOrVideo,
    this.onOpenWorkspace,
    this.capturing = false,
    this.onToggleVoice,
    super.key,
  });

  final TextEditingController controller;
  final ValueChanged<String> onSend;
  final bool voiceCaptureAvailable;
  final String? voiceUnavailableReason;
  final String? voiceRecoveryAction;
  final VoidCallback? onOpenVoiceSettings;
  final VoidCallback? onUploadFile;
  final VoidCallback? onPickPhotoOrVideo;
  final VoidCallback? onOpenWorkspace;
  final bool capturing;
  final VoidCallback? onToggleVoice;

  @override
  State<TranscriptComposer> createState() => _TranscriptComposerState();
}

class _TranscriptComposerState extends State<TranscriptComposer> {
  bool _showEmoji = false;

  TranscriptComposerPresentation _presentation() {
    return TranscriptComposerPresentation.fromState(
      voiceCaptureAvailable: widget.voiceCaptureAvailable,
      voiceUnavailableReason: widget.voiceUnavailableReason,
      voiceRecoveryAction: widget.voiceRecoveryAction,
      canOpenVoiceSettings: widget.onOpenVoiceSettings != null,
      capturing: widget.capturing,
      emojiOpen: _showEmoji,
    );
  }

  void _showVoiceUnavailable(BuildContext context) {
    final presentation = _presentation();
    showModalBottomSheet<void>(
      context: context,
      showDragHandle: true,
      builder: (context) => TranscriptBottomSheetList(
        children: [
          Text(
            presentation.voiceSheetTitle,
            style: Theme.of(context).textTheme.titleLarge,
          ),
          const SizedBox(height: 12),
          for (final row in presentation.voiceSheetRows)
            ListTile(
              contentPadding: EdgeInsets.zero,
              leading: Icon(_voiceSheetIcon(row.kind)),
              title: Text(row.title),
              subtitle: Text(row.subtitle),
              onTap: _voiceSheetTap(context, row.actionKind),
            ),
        ],
      ),
    );
  }

  void _showShareSheet(BuildContext context) {
    final parentContext = context;
    final presentation = _presentation();
    showModalBottomSheet<void>(
      context: context,
      showDragHandle: true,
      builder: (context) => TranscriptBottomSheetList(
        children: [
          Text(
            presentation.shareTitle,
            style: Theme.of(context).textTheme.titleLarge,
          ),
          const SizedBox(height: 12),
          for (final option in presentation.shareOptions)
            ListTile(
              leading: Icon(_shareIcon(option.kind)),
              title: Text(option.title),
              subtitle: Text(option.subtitle),
              onTap: () => _handleShareOption(
                sheetContext: context,
                parentContext: parentContext,
                kind: option.kind,
              ),
            ),
        ],
      ),
    );
  }

  void _handleShareOption({
    required BuildContext sheetContext,
    required BuildContext parentContext,
    required TranscriptComposerShareOptionKind kind,
  }) {
    Navigator.of(sheetContext).pop();
    switch (kind) {
      case TranscriptComposerShareOptionKind.uploadFile:
        final callback = widget.onUploadFile;
        if (callback != null) {
          callback();
          return;
        }
        _showDeferredShareUnavailable(
          parentContext,
          title: 'File upload unavailable',
          message:
              'Gormes has not advertised a Navivox upload endpoint yet. Use text or workspace references for now.',
        );
      case TranscriptComposerShareOptionKind.photoOrVideo:
        final callback = widget.onPickPhotoOrVideo;
        if (callback != null) {
          callback();
          return;
        }
        _showDeferredShareUnavailable(
          parentContext,
          title: 'Photo upload unavailable',
          message:
              'Photo and video picking is ready to plug into the upload endpoint once Gormes enables uploads.',
        );
      case TranscriptComposerShareOptionKind.workspaceFile:
        final callback = widget.onOpenWorkspace;
        if (callback != null) {
          callback();
          return;
        }
        _showDeferredShareUnavailable(
          parentContext,
          title: 'Workspace browser unavailable',
          message:
              'Select a profile contact with workspace roots before browsing workspace files.',
        );
    }
  }

  void _showDeferredShareUnavailable(
    BuildContext context, {
    required String title,
    required String message,
  }) {
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      showModalBottomSheet<void>(
        context: context,
        showDragHandle: true,
        builder: (context) => TranscriptBottomSheetList(
          children: [
            ListTile(
              contentPadding: EdgeInsets.zero,
              leading: const Icon(Icons.info_outline),
              title: Text(title),
              subtitle: Text(message),
            ),
          ],
        ),
      );
    });
  }

  IconData _shareIcon(TranscriptComposerShareOptionKind kind) {
    return switch (kind) {
      TranscriptComposerShareOptionKind.uploadFile => Icons.upload_file,
      TranscriptComposerShareOptionKind.photoOrVideo =>
        Icons.photo_library_outlined,
      TranscriptComposerShareOptionKind.workspaceFile => Icons.folder_open,
    };
  }

  IconData _voiceSheetIcon(TranscriptComposerVoiceSheetRowKind kind) {
    return switch (kind) {
      TranscriptComposerVoiceSheetRowKind.status => Icons.mic_off,
      TranscriptComposerVoiceSheetRowKind.recoveryAction =>
        Icons.tips_and_updates_outlined,
      TranscriptComposerVoiceSheetRowKind.openVoiceSettings =>
        Icons.settings_voice_outlined,
    };
  }

  VoidCallback? _voiceSheetTap(
    BuildContext context,
    TranscriptComposerVoiceSheetActionKind? actionKind,
  ) {
    return switch (actionKind) {
      TranscriptComposerVoiceSheetActionKind.openVoiceSettings => () {
        Navigator.of(context).pop();
        widget.onOpenVoiceSettings?.call();
      },
      null => null,
    };
  }

  void _insertEmoji(String emoji) {
    final value = widget.controller.value;
    final selection = value.selection;
    final start = selection.isValid ? selection.start : value.text.length;
    final end = selection.isValid ? selection.end : value.text.length;
    final text = value.text.replaceRange(start, end, emoji);
    final offset = start + emoji.length;
    widget.controller.value = TextEditingValue(
      text: text,
      selection: TextSelection.collapsed(offset: offset),
    );
  }

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);
    final presentation = _presentation();
    return Container(
      padding: const EdgeInsets.fromLTRB(8, 8, 8, 8),
      decoration: BoxDecoration(
        color: theme.colorScheme.surface,
        border: Border(
          top: BorderSide(color: theme.colorScheme.outlineVariant, width: 0.5),
        ),
      ),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        children: [
          if (presentation.showEmoji)
            SizedBox(
              height: 44,
              child: ListView.separated(
                scrollDirection: Axis.horizontal,
                itemCount: presentation.quickEmoji.length,
                separatorBuilder: (context, index) => const SizedBox(width: 4),
                itemBuilder: (context, index) {
                  final emoji = presentation.quickEmoji[index];
                  return TextButton(
                    onPressed: () => _insertEmoji(emoji),
                    child: Text(emoji, style: const TextStyle(fontSize: 22)),
                  );
                },
              ),
            ),
          Row(
            crossAxisAlignment: CrossAxisAlignment.end,
            children: [
              IconButton(
                tooltip: presentation.emojiTooltip,
                onPressed: () => setState(() => _showEmoji = !_showEmoji),
                icon: Icon(
                  _showEmoji ? Icons.keyboard : Icons.emoji_emotions_outlined,
                ),
              ),
              Expanded(
                child: TextField(
                  controller: widget.controller,
                  maxLines: null,
                  textInputAction: TextInputAction.send,
                  decoration: InputDecoration(
                    hintText: presentation.messageHint,
                    border: OutlineInputBorder(
                      borderRadius: BorderRadius.circular(24),
                      borderSide: BorderSide.none,
                    ),
                    filled: true,
                    fillColor: theme.colorScheme.surfaceContainerHighest,
                    contentPadding: const EdgeInsets.symmetric(
                      horizontal: 16,
                      vertical: 8,
                    ),
                  ),
                  onSubmitted: widget.onSend,
                ),
              ),
              IconButton(
                tooltip: presentation.attachTooltip,
                onPressed: () => _showShareSheet(context),
                icon: const Icon(Icons.attach_file),
              ),
              if (presentation.voiceAvailable)
                IconButton.filledTonal(
                  onPressed: widget.onToggleVoice,
                  icon: Icon(
                    presentation.voiceButtonState ==
                            TranscriptComposerVoiceButtonState.stop
                        ? Icons.stop
                        : Icons.mic,
                  ),
                  style: IconButton.styleFrom(
                    backgroundColor:
                        presentation.voiceButtonState ==
                            TranscriptComposerVoiceButtonState.stop
                        ? theme.colorScheme.errorContainer
                        : null,
                  ),
                )
              else
                IconButton.outlined(
                  tooltip: presentation.voiceTooltip,
                  onPressed: () => _showVoiceUnavailable(context),
                  icon: const Icon(Icons.mic_off),
                ),
              const SizedBox(width: 4),
              IconButton.filled(
                onPressed: () => widget.onSend(widget.controller.text),
                icon: const Icon(Icons.send, size: 20),
              ),
            ],
          ),
        ],
      ),
    );
  }
}

import 'package:flutter/material.dart';

import '../../../../../shared/voice/voice_capture_service.dart';
import '../../../voice/controllers/transcript_voice_capture_flow.dart';
import 'transcript_composer.dart';

class TranscriptInputPanel extends StatefulWidget {
  const TranscriptInputPanel({
    required this.controller,
    required this.onSend,
    this.voiceCaptureService,
    this.onVoice,
    this.onVoiceCaptureStarted,
    this.onVoiceCaptureFailed,
    this.voiceCaptureTimeout = const Duration(seconds: 30),
    this.voiceUnavailableReason,
    this.voiceRecoveryAction,
    this.onOpenVoiceSettings,
    this.onUploadFile,
    this.onPickPhotoOrVideo,
    this.onOpenWorkspace,
    super.key,
  });

  final TextEditingController controller;
  final ValueChanged<String> onSend;
  final VoiceCaptureService? voiceCaptureService;
  final ValueChanged<VoiceCapture>? onVoice;
  final VoidCallback? onVoiceCaptureStarted;
  final ValueChanged<Object>? onVoiceCaptureFailed;
  final Duration voiceCaptureTimeout;
  final String? voiceUnavailableReason;
  final String? voiceRecoveryAction;
  final VoidCallback? onOpenVoiceSettings;
  final VoidCallback? onUploadFile;
  final VoidCallback? onPickPhotoOrVideo;
  final VoidCallback? onOpenWorkspace;

  @override
  State<TranscriptInputPanel> createState() => _TranscriptInputPanelState();
}

class _TranscriptInputPanelState extends State<TranscriptInputPanel> {
  final _voiceCaptureFlow = const TranscriptVoiceCaptureFlow();
  bool _capturing = false;
  String? _captureError;

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);
    return Column(
      mainAxisSize: MainAxisSize.min,
      children: [
        if (_captureError != null)
          Padding(
            padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 4),
            child: Text(
              _captureError!,
              style: TextStyle(color: theme.colorScheme.error, fontSize: 12),
            ),
          ),
        SafeArea(
          top: false,
          child: TranscriptComposer(
            controller: widget.controller,
            onSend: _send,
            voiceCaptureAvailable: widget.voiceCaptureService != null,
            voiceUnavailableReason: widget.voiceUnavailableReason,
            voiceRecoveryAction: widget.voiceRecoveryAction,
            onOpenVoiceSettings: widget.onOpenVoiceSettings,
            onUploadFile: widget.onUploadFile,
            onPickPhotoOrVideo: widget.onPickPhotoOrVideo,
            onOpenWorkspace: widget.onOpenWorkspace,
            capturing: _capturing,
            onToggleVoice: _toggleVoiceCapture,
          ),
        ),
      ],
    );
  }

  void _send(String text) {
    widget.onSend(text);
    widget.controller.clear();
  }

  Future<void> _toggleVoiceCapture() async {
    if (widget.voiceCaptureService == null) return;

    if (_capturing) {
      setState(() => _capturing = false);
      return;
    }

    setState(() {
      _capturing = true;
      _captureError = null;
    });
    final outcome = await _voiceCaptureFlow.capture(
      service: widget.voiceCaptureService,
      timeout: widget.voiceCaptureTimeout,
      onStarted: widget.onVoiceCaptureStarted,
    );
    try {
      switch (outcome.status) {
        case TranscriptVoiceCaptureStatus.unavailable:
          return;
        case TranscriptVoiceCaptureStatus.captured:
          if (!mounted) return;
          final capture = outcome.capture;
          if (capture != null) widget.onVoice?.call(capture);
          break;
        case TranscriptVoiceCaptureStatus.failed:
          if (mounted) {
            setState(() => _captureError = outcome.errorMessage);
          }
          final error = outcome.error;
          if (error != null) widget.onVoiceCaptureFailed?.call(error);
          break;
      }
    } finally {
      if (mounted) setState(() => _capturing = false);
    }
  }
}

import 'dart:async';

import 'package:flutter/material.dart';

import '../../../../../core/channel/navivox_channel.dart';
import '../../presentation/transcript_message_action_presentation.dart';
import '../shared/transcript_bottom_sheet_list.dart';

class TranscriptMessageActionSheet extends StatelessWidget {
  const TranscriptMessageActionSheet({
    required this.presentation,
    this.onPauseStream,
    this.onCopyText,
    this.onReadAloud,
    this.onInspectRunRecord,
    this.onForward,
    this.scrollController,
    super.key,
  });

  final TranscriptMessageActionPresentation presentation;
  final FutureOr<void> Function()? onPauseStream;
  final FutureOr<void> Function()? onCopyText;
  final FutureOr<void> Function()? onReadAloud;
  final FutureOr<void> Function()? onInspectRunRecord;
  final void Function(NavivoxProfileContact target)? onForward;
  final ScrollController? scrollController;

  @override
  Widget build(BuildContext context) {
    return TranscriptBottomSheetList(
      controller: scrollController,
      children: [
        Text(presentation.title, style: Theme.of(context).textTheme.titleLarge),
        const SizedBox(height: 12),
        if (presentation.hasText)
          Container(
            padding: const EdgeInsets.all(12),
            decoration: BoxDecoration(
              color: Theme.of(context).colorScheme.surfaceContainerHigh,
              borderRadius: BorderRadius.circular(16),
            ),
            child: SelectableText(presentation.text),
          ),
        if (presentation.showPauseStream)
          ListTile(
            leading: const Icon(Icons.pause_circle_outline),
            title: Text(presentation.pauseLabel),
            subtitle: Text(presentation.pauseSubtitle),
            onTap: onPauseStream,
          ),
        if (presentation.showCopy) ...[
          ListTile(
            leading: const Icon(Icons.copy),
            title: Text(presentation.copyLabel),
            onTap: onCopyText,
          ),
          if (presentation.canReadAloud)
            ListTile(
              leading: const Icon(Icons.volume_up),
              title: Text(presentation.readAloudLabel),
              onTap: onReadAloud,
            ),
        ],
        if (presentation.showForwardSection) ...[
          const Divider(),
          ListTile(
            leading: const Icon(Icons.forward),
            title: Text(presentation.forwardTitle),
          ),
          for (final target in presentation.forwardTargets)
            ListTile(
              leading: const CircleAvatar(child: Icon(Icons.person)),
              title: Text(target.displayName),
              subtitle: Text(target.subtitle),
              onTap: () => onForward?.call(target.contact),
            ),
        ],
        if (presentation.showInspectRunRecord)
          ListTile(
            leading: const Icon(Icons.fact_check_outlined),
            title: Text(presentation.inspectRunRecordLabel),
            subtitle: Text(presentation.inspectRunRecordSubtitle),
            onTap: onInspectRunRecord,
          ),
        if (presentation.showReadAloudUnavailable)
          ListTile(
            enabled: false,
            leading: const Icon(Icons.volume_off),
            title: Text(presentation.readAloudUnavailableLabel),
            subtitle: Text(presentation.readAloudUnavailableSubtitle),
          ),
      ],
    );
  }
}

import 'package:flutter/material.dart';

import '../../../../../core/gateway/navivox_gateway_protocol.dart';
import '../../presentation/transcript_run_record_presentation.dart';

class TranscriptRunRecordSheet extends StatelessWidget {
  const TranscriptRunRecordSheet({
    required this.record,
    this.scrollController,
    super.key,
  });

  final NavivoxRunRecordSnapshot record;
  final ScrollController? scrollController;

  @override
  Widget build(BuildContext context) {
    final presentation = TranscriptRunRecordPresentation.fromRecord(record);
    final theme = Theme.of(context);
    return SafeArea(
      child: SingleChildScrollView(
        key: const ValueKey('transcript-run-record-scroll'),
        controller: scrollController,
        padding: const EdgeInsets.fromLTRB(16, 0, 16, 16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Text(presentation.title, style: theme.textTheme.titleLarge),
            const SizedBox(height: 12),
            _Section(
              title: 'Identity',
              children: [
                _InfoTile(label: 'Run ID', value: presentation.runId),
                _InfoTile(label: 'Session ID', value: presentation.sessionId),
                _InfoTile(label: 'Status', value: presentation.statusLabel),
              ],
            ),
            _Section(
              title: 'Timeline',
              children: [
                _InfoTile(label: 'Created', value: presentation.createdAtLabel),
                _InfoTile(label: 'Updated', value: presentation.updatedAtLabel),
                _InfoTile(
                  label: 'Completed',
                  value: presentation.completedAtLabel,
                ),
              ],
            ),
            _Section(
              title: 'Provider',
              children: [
                _InfoTile(
                  label: 'Provider usage',
                  value: presentation.providerUsageLabel,
                ),
                _InfoTile(
                  label: 'Provider cost',
                  value: presentation.providerCostLabel,
                ),
              ],
            ),
            if (presentation.transcriptRows.isNotEmpty)
              _Section(
                title: 'Transcript',
                children: [
                  for (final row in presentation.transcriptRows)
                    ListTile(
                      dense: true,
                      contentPadding: EdgeInsets.zero,
                      leading: const Icon(Icons.chat_bubble_outline),
                      title: Text(row.role),
                      subtitle: SelectableText(row.text),
                    ),
                ],
              ),
            _Section(
              title: 'Voice',
              children: [
                for (final row in presentation.voiceRows)
                  _InfoTile(label: row.label, value: row.value),
              ],
            ),
            if (presentation.toolRows.isNotEmpty)
              _Section(
                title: 'Tool timeline',
                children: [
                  for (final row in presentation.toolRows)
                    ListTile(
                      dense: true,
                      contentPadding: EdgeInsets.zero,
                      leading: const Icon(Icons.build_outlined),
                      title: Text(row.name),
                      subtitle: Text('${row.status} • ${row.artifactRef}'),
                    ),
                ],
              ),
          ],
        ),
      ),
    );
  }
}

class _Section extends StatelessWidget {
  const _Section({required this.title, required this.children});

  final String title;
  final List<Widget> children;

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);
    return Padding(
      padding: const EdgeInsets.only(bottom: 12),
      child: DecoratedBox(
        decoration: BoxDecoration(
          border: Border.all(color: theme.colorScheme.outlineVariant),
          borderRadius: BorderRadius.circular(16),
        ),
        child: Padding(
          padding: const EdgeInsets.fromLTRB(12, 10, 12, 6),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text(
                title,
                style: theme.textTheme.titleSmall?.copyWith(
                  color: theme.colorScheme.primary,
                  fontWeight: FontWeight.w700,
                ),
              ),
              const SizedBox(height: 4),
              ...children,
            ],
          ),
        ),
      ),
    );
  }
}

class _InfoTile extends StatelessWidget {
  const _InfoTile({required this.label, required this.value});

  final String label;
  final String value;

  @override
  Widget build(BuildContext context) {
    return ListTile(
      dense: true,
      contentPadding: EdgeInsets.zero,
      title: Text(label),
      subtitle: SelectableText(value),
    );
  }
}

